import { existsSync, unlinkSync } from 'node:fs';
import { resolve } from 'node:path';

/** Generated by `npm run i18n:queue:verify` / manual queue i18n steps in cwd. */
const FILES_DEFAULT = ['queue-i18n-smoke-summary.json', 'queue-i18n-report.json'];

/** Optional local CI-parity / baseline replay outputs (use `--all`). */
const FILES_ALL_EXTRA = [
  'queue-i18n-baseline-metadata.json',
  'queue-i18n-smoke-summary-previous.json',
  'queue-i18n-report-previous.json',
  'queue-i18n-artifacts.json',
  'queue-i18n-smoke-previous.zip',
];

function main() {
  const all = process.argv.includes('--all');
  const names = all ? [...FILES_DEFAULT, ...FILES_ALL_EXTRA] : FILES_DEFAULT;
  for (const name of names) {
    const p = resolve(process.cwd(), name);
    if (existsSync(p)) {
      unlinkSync(p);
      process.stdout.write(`removed ${name}\n`);
    }
  }
  process.stdout.write(
    all
      ? 'PASS queue i18n verify artifact clean (--all)\n'
      : 'PASS queue i18n verify artifact clean\n',
  );
}

try {
  main();
} catch (error) {
  process.stderr.write(`FAIL queue i18n verify artifact clean: ${error.message}\n`);
  process.exitCode = 1;
}
